mapper.select:
select id, title, category, content, create_time as createTime, update_time as updateTime, create_user as createUser, update_user as updateUser from ai_knowledge_base
and (title like concat('%', #{criteria.keyword}, '%') or content like concat('%', #{criteria.keyword}, '%'))
and category = #{criteria.category}
order by ${criteria.sortColumn} ${criteria.sortDirection}, id desc limit #{criteria.limit} offset #{criteria.offset}

select count(1) from ai_knowledge_base
and (title like concat('%', #{criteria.keyword}, '%') or content like concat('%', #{criteria.keyword}, '%'))
and category = #{criteria.category}

select id, title, category, content, create_time as createTime, update_time as updateTime, create_user as createUser, update_user as updateUser from ai_knowledge_base
and (title like concat('%', #{keyword}, '%') or category like concat('%', #{keyword}, '%') or content like concat('%', #{keyword}, '%'))
order by update_time desc, id desc limit #{limit}

select id, admin_user_id as adminUserId, title, create_time as createTime, update_time as updateTime
from ai_ops_chat_session
where id = #{id}
  and admin_user_id = #{adminUserId}

mapper.update:
update ai_ops_chat_session
set update_time = now()
where id = #{id}

mapper.select:
select id, session_id as sessionId, role, content, provider, model, references_json as referencesJson, create_time as createTime
from ai_ops_chat_message
where session_id = #{sessionId}
order by create_time asc, id asc
limit #{limit}

select id, suggestion_id as suggestionId, status, actor_id as actorId, create_time as createTime, update_time as updateTime
from ai_ops_suggestion_action
where suggestion_id = #{suggestionId}

mapper.insert:
insert into ai_ops_suggestion_action_log(
    suggestion_id, action, status, target_type, target_id, target_name,
    operation_summary, operation_payload, actor_id, create_time
)
values(
    #{suggestionId}, #{action}, #{status}, #{targetType}, #{targetId}, #{targetName},
    #{operationSummary}, #{operationPayload}, #{actorId}, #{createTime}
)
